#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
const ll INF = 1e18;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, M;
    cin >> N >> M;
    vector<vector<pair<int, ll>>> g(N);
    vector<tuple<int, int, ll>> edges;
    for (int i = 0; i < M; i++) {
        int a, b;
        ll l;
        cin >> a >> b >> l;
        a--; b--;
        g[a].push_back({b, l});
        g[b].push_back({a, l});
        edges.push_back({a, b, l});
    }

    // Dijkstra from 1 to N
    auto dijkstra = [&](int start, int forbid_a, int forbid_b, ll forbid_len) -> vector<ll> {
        vector<ll> dist(N, INF);
        dist[start] = 0;
        priority_queue<pair<ll, int>, vector<pair<ll, int>>, greater<pair<ll, int>>> pq;
        pq.push({0, start});
        while (!pq.empty()) {
            auto [d, u] = pq.top();
            pq.pop();
            if (d != dist[u]) continue;
            for (auto [v, w] : g[u]) {
                // If this edge is the blocked one, use doubled length
                ll ww = w;
                if ((u == forbid_a && v == forbid_b) || (u == forbid_b && v == forbid_a)) {
                    if (w == forbid_len) {
                        ww = w * 2;
                    }
                }
                if (dist[v] > dist[u] + ww) {
                    dist[v] = dist[u] + ww;
                    pq.push({dist[v], v});
                }
            }
        }
        return dist;
    };

    // Get original shortest path
    vector<ll> dist0 = dijkstra(0, -1, -1, -1);
    ll orig = dist0[N-1];

    // Reconstruct one shortest path tree to identify edges on some shortest path
    // Use parent array
    vector<int> parent(N, -1);
    vector<ll> dist_for_parent(N, INF);
    dist_for_parent[0] = 0;
    priority_queue<pair<ll, int>, vector<pair<ll, int>>, greater<pair<ll, int>>> pq;
    pq.push({0, 0});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d != dist_for_parent[u]) continue;
        for (auto [v, w] : g[u]) {
            if (dist_for_parent[v] > dist_for_parent[u] + w) {
                dist_for_parent[v] = dist_for_parent[u] + w;
                parent[v] = u;
                pq.push({dist_for_parent[v], v});
            }
        }
    }

    // Collect edges on shortest path from 1 to N
    vector<pair<int,int>> path_edges;
    {
        int v = N-1;
        while (v != 0) {
            int u = parent[v];
            path_edges.push_back({u, v});
            v = u;
        }
    }

    ll best = 0;
    // Only edges on the original shortest path matter for increase
    for (auto [a, b] : path_edges) {
        // Find the length of this edge
        ll len = -1;
        for (auto [v, w] : g[a]) {
            if (v == b) {
                len = w;
                break;
            }
        }
        vector<ll> distb = dijkstra(0, a, b, len);
        ll new_dist = distb[N-1];
        best = max(best, new_dist - orig);
    }

    cout << best << "\n";
    return 0;
}
